int output_device_info(int device_id)
{
    cudaDeviceProp prop;
    cudaError_t err = cudaGetDeviceProperties(&prop, device_id);
    if (err != cudaSuccess) {
        printf("Error: Failed to access device properties!\n");
        return -1;
    }
    printf(" \n Device is  %s \n", prop.name);
    printf(" %s \n", prop.name);
    printf(" Compute Units (SMs): %d \n", prop.multiProcessorCount);
    return 0;
}

void fatal(char *s)
{
  fprintf(stderr, "Error: %s\n", s);
}

void readinput(float *vect, int grid_rows, int grid_cols, int layers, char *file) {
    int i,j,k;
    FILE *fp;
    char str[STR_SIZE];
    float val;

    if( (fp  = fopen(file, "r" )) ==0 )
      fatal( "The file was not opened" );

    for (i=0; i <= grid_rows-1; i++) 
      for (j=0; j <= grid_cols-1; j++)
        for (k=0; k <= layers-1; k++)
          {
            if (fgets(str, STR_SIZE, fp) == NULL) fatal("Error reading file\n");
            if (feof(fp))
              fatal("not enough lines in file");

            if ((sscanf(str, "%f", &val) != 1))
              fatal("invalid file format");
            vect[i*grid_cols+j+k*grid_rows*grid_cols] = val;
          }

    fclose(fp);	
}

void writeoutput(float *vect, int grid_rows, int grid_cols, int layers, char *file) {
    int i,j,k, index=0;
    FILE *fp;
    char str[STR_SIZE];

    if( (fp = fopen(file, "w" )) == 0 )
      printf( "The file was not opened\n" );

    for (i=0; i < grid_rows; i++) 
      for (j=0; j < grid_cols; j++)
        for (k=0; k < layers; k++)
          {
            sprintf(str, "%d\t%g\n", index, vect[i*grid_cols+j+k*grid_rows*grid_cols]);
            fputs(str,fp);
            index++;
          }

    fclose(fp);	
}

void computeTempCPU(float *pIn, float* tIn, float *tOut, 
        int nx, int ny, int nz, float Cap, 
        float Rx, float Ry, float Rz, 
        float dt, float amb_temp, int numiter) 
{   
    float ce, cw, cn, cs, ct, cb, cc;
    float stepDivCap = dt / Cap;
    ce = cw =stepDivCap/ Rx;
    cn = cs =stepDivCap/ Ry;
    ct = cb =stepDivCap/ Rz;
    cc = 1.0 - (2.0*ce + 2.0*cn + 3.0*ct);

    int c,w,e,n,s,b,t;
    int x,y,z;
    int i = 0;
    float *tempCopy = (float*)malloc(nx * ny * nz * sizeof(float));
    memcpy(tempCopy, tIn, nx * ny * nz * sizeof(float));

    float *currentIn = tempCopy;
    float *currentOut = tOut;

    do{
        for(z = 0; z < nz; z++)
            for(y = 0; y < ny; y++)
                for(x = 0; x < nx; x++)
                {
                    c = x + y * nx + z * nx * ny;
                    w = (x == 0) ? c : c - 1;
                    e = (x == nx - 1) ? c : c + 1;
                    n = (y == 0) ? c : c - nx;
                    s = (y == ny - 1) ? c : c + nx;
                    b = (z == 0) ? c : c - nx * ny;
                    t = (z == nz - 1) ? c : c + nx * ny;
                    currentOut[c] = currentIn[c]*cc + currentIn[n]*cn + currentIn[s]*cs + currentIn[e]*ce + currentIn[w]*cw + currentIn[t]*ct + currentIn[b]*cb + (dt/Cap) * pIn[c] + ct*amb_temp;
                }
        float *temp = currentIn;
        currentIn = currentOut;
        currentOut = temp; 
        i++;
    }
    while(i < numiter);

    if (i % 2 == 1) {
        memcpy(tOut, currentIn, nx * ny * nz * sizeof(float));
    }
    free(tempCopy);
}

float accuracy(float *arr1, float *arr2, int len)
{
    float err = 0.0; 
    int i;
    for(i = 0; i < len; i++)
    {
        err += (arr1[i]-arr2[i]) * (arr1[i]-arr2[i]);
    }
    return (float)sqrt(err/len);
}

long long get_time() {
	struct timeval tv;
	gettimeofday(&tv, NULL);
	return (tv.tv_sec * 1000000) + tv.tv_usec;
}

void tvsub(struct timeval *t1, struct timeval *t0, struct timeval *t) {
    t->tv_sec = t1->tv_sec - t0->tv_sec;
    t->tv_usec = t1->tv_usec - t0->tv_usec;
    if (t->tv_usec < 0) {
        t->tv_sec--;
        t->tv_usec += 1000000;
    }
}

int main(int argc, char** argv)
{
    char *pfile = NULL, *tfile = NULL, *ofile = NULL;
    int iterations = 0;
    int numCols    = 0;
    int numRows    = 0;
    int layers     = 0;

    int device_id_inuse = 0;              

    int cur_arg;
	for (cur_arg = 1; argc > cur_arg; cur_arg++) {
        if (0 == strcmp(argv[cur_arg], "-h")) {
			usage(argc, argv);
        }
        else if (0 == strcmp(argv[cur_arg], "-n")) {
            if (cur_arg + 1 <= argc) {
                numCols = numRows = atoi(argv[cur_arg+1]);
                cur_arg++;
            }
        }
        else if (0 == strcmp(argv[cur_arg], "-l")) {
            if (cur_arg + 1 <= argc) {
                layers = atoi(argv[cur_arg+1]);
                cur_arg++;
            }
        }
        else if (0 == strcmp(argv[cur_arg], "-i")) {
            if (cur_arg + 1 <= argc) {
                iterations = atoi(argv[cur_arg+1]);
                cur_arg++;
            }
        }
        else if (0 == strcmp(argv[cur_arg], "-f")) {
            if (cur_arg + 3 <= argc) {
                pfile = argv[cur_arg+1];
                tfile = argv[cur_arg+2];
                ofile = argv[cur_arg+3];
                cur_arg = cur_arg + (3);
            }
        }
        else if (0 == strcmp(argv[cur_arg], "-d")) {
            if (cur_arg + 1 <= argc) {
                device_id_inuse = atoi(argv[cur_arg+1]);
                cur_arg++;
            }
        }
    }

	if (0 == numCols || 0 == layers || 0 == iterations || NULL == pfile) {
		usage(argc, argv);
	}

  float dx         = chip_height/numRows;
  float dy         = chip_width/numCols;
  float dz         = t_chip/layers;

  float Cap        = FACTOR_CHIP * SPEC_HEAT_SI * t_chip * dx * dy;
  float Rx         = dy / (2.0 * K_SI * t_chip * dx);
  float Ry         = dx / (2.0 * K_SI * t_chip * dy);
  float Rz         = dz / (K_SI * dx * dy);

  float max_slope  = MAX_PD / (FACTOR_CHIP * t_chip * SPEC_HEAT_SI);
  float dt         = PRECISION / max_slope;

  float ce, cw, cn, cs, ct, cb, cc;
  float stepDivCap = dt / Cap;
  ce               = cw                                              = stepDivCap/ Rx;
  cn               = cs                                              = stepDivCap/ Ry;
  ct               = cb                                              = stepDivCap/ Rz;
  cc               = 1.0 - (2.0*ce + 2.0*cn + 3.0*ct);

  int size = numCols * numRows * layers;
  float* tIn      = (float*) calloc(size,sizeof(float));
  float* pIn      = (float*) calloc(size,sizeof(float));
  float* tempCopy = (float*)malloc(size * sizeof(float));
  float* tempOut  = (float*) calloc(size,sizeof(float));

  readinput(tIn,numRows, numCols, layers, tfile);
  readinput(pIn,numRows, numCols, layers, pfile);

  dim3 global(numCols, numRows);                   
  dim3 local(WG_SIZE_X, WG_SIZE_Y);
  memcpy(tempCopy,tIn, size * sizeof(float));

  int device_count = 0;
  cudaError_t cuda_err = cudaGetDeviceCount(&device_count);
  if (cuda_err != cudaSuccess || device_count <= 0) {
      printf("Error: Failed to find a CUDA device!\n%s\n", err_code(cuda_err));
      return EXIT_FAILURE;
  }

  if (device_id_inuse >= device_count) {
      printf("Invalid Device Number\n");
      return EXIT_FAILURE;
  }

  cuda_err = cudaSetDevice(device_id_inuse);
  if (cuda_err != cudaSuccess) {
      printf("Error: Failed to set device!\n%s\n", err_code(cuda_err));
      return EXIT_FAILURE;
  }

  output_device_info(device_id_inuse);

#ifdef TIMING
  struct timeval tv;
  struct timeval tv_total_start, tv_total_end;
  struct timeval tv_init_end;
  struct timeval tv_h2d_start, tv_h2d_end;
  struct timeval tv_d2h_start, tv_d2h_end;
  struct timeval tv_kernel_start, tv_kernel_end;
  struct timeval tv_mem_alloc_start, tv_mem_alloc_end;
  struct timeval tv_close_start, tv_close_end;
  float init_time = 0, mem_alloc_time = 0, h2d_time = 0, kernel_time = 0,
              d2h_time = 0, close_time = 0, total_time = 0;

  gettimeofday(&tv_total_start, NULL);
#endif

#ifdef  TIMING
  gettimeofday(&tv_init_end, NULL);
  tvsub(&tv_init_end, &tv_total_start, &tv);
  init_time = tv.tv_sec * 1000.0 + (float) tv.tv_usec / 1000.0;
#endif

  float *d_a, *d_b, *d_c;
  cuda_err = cudaMalloc(&d_a, sizeof(float) * size);
  cuda_err |= cudaMalloc(&d_b, sizeof(float) * size);
  cuda_err |= cudaMalloc(&d_c, sizeof(float) * size);

  if (cuda_err != cudaSuccess) {
      printf("Error: Failed to allocate device memory!\n%s\n", err_code(cuda_err));
      exit(1);
  }

#ifdef  TIMING
  gettimeofday(&tv_mem_alloc_end, NULL);
  tvsub(&tv_mem_alloc_end, &tv_init_end, &tv);
  mem_alloc_time = tv.tv_sec * 1000.0 + (float) tv.tv_usec / 1000.0;
#endif

  cuda_err = cudaMemcpy(d_a, tIn, sizeof(float) * size, cudaMemcpyHostToDevice);
  if (cuda_err != cudaSuccess) {
      printf("Error: Failed to write tIn to source array!\n%s\n", err_code(cuda_err));
      exit(1);
  }

  cuda_err = cudaMemcpy(d_b, pIn, sizeof(float) * size, cudaMemcpyHostToDevice);
  if (cuda_err != cudaSuccess) {
      printf("Error: Failed to write pIn to source array!\n%s\n", err_code(cuda_err));
      exit(1);
  }

  cuda_err = cudaMemcpy(d_c, tempOut, sizeof(float) * size, cudaMemcpyHostToDevice);
  if (cuda_err != cudaSuccess) {
      printf("Error: Failed to write tempOut to source array!\n%s\n", err_code(cuda_err));
      exit(1);
  }

  int j;
  for(j = 0; j < iterations; j++)
    {
      hotspotOpt1<<<global, local>>>(d_b, d_a, d_c, stepDivCap, numCols, numRows, layers, ce, cw, cn, cs, ct, cb, cc, amb_temp);

      cuda_err = cudaGetLastError();
      if (cuda_err != cudaSuccess) {
          printf("Error: Failed to execute kernel!\n%s\n", err_code(cuda_err));
          return EXIT_FAILURE;
      }

      float *temp = d_a;
      d_a         = d_c;
      d_c         = temp;
    }

  cuda_err = cudaDeviceSynchronize();
  if (cuda_err != cudaSuccess) {
      printf("Error: Failed to synchronize!\n%s\n", err_code(cuda_err));
      return EXIT_FAILURE;
  }

  cuda_err = cudaMemcpy(tempOut, d_c, sizeof(float) * size, cudaMemcpyDeviceToHost);
  if (cuda_err != cudaSuccess) {
      printf("Error: Failed to read output array!\n%s\n", err_code(cuda_err));
      exit(1);
  }

#ifdef  TIMING
  gettimeofday(&tv_close_start, NULL);
#endif
  cudaFree(d_a);
  cudaFree(d_b);
  cudaFree(d_c);

#ifdef  TIMING
  gettimeofday(&tv_close_end, NULL);
  tvsub(&tv_close_end, &tv_close_start, &tv);
  close_time = tv.tv_sec * 1000.0 + (float) tv.tv_usec / 1000.0;
  tvsub(&tv_close_end, &tv_total_start, &tv);
  total_time = tv.tv_sec * 1000.0 + (float) tv.tv_usec / 1000.0;

  printf("Init: %f\n", init_time);
  printf("MemAlloc: %f\n", mem_alloc_time);
  printf("HtoD: %f\n", h2d_time);
  printf("Exec: %f\n", kernel_time);
  printf("DtoH: %f\n", d2h_time);
  printf("Close: %f\n", close_time);
  printf("Total: %f\n", total_time);
#endif

  float* answer = (float*)calloc(size, sizeof(float));
  computeTempCPU(pIn, tempCopy, answer, numCols, numRows, layers, Cap, Rx, Ry, Rz, dt, amb_temp, iterations);
  float acc = accuracy(tempOut,answer,numRows*numCols*layers);
  printf("Accuracy: %e\n",acc);

  writeoutput(tempOut,numRows,numCols,layers,ofile);

  return 0;
}
